async (page) => {
  // Click east to walk toward Villager at ~198, 114. I'm at 170, 120
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 1100, y: 360 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({
      pos: s.player_position,
      nearby: s.nearby_entities ? s.nearby_entities.slice(0, 15).map(e => ({
        name: e.name, type: e.type, dist: e.distance, cx: e.click_x, cy: e.click_y, on_screen: e.on_screen, quest_npc: e.quest_npc
      })) : []
    });
  });
  return state;
}

async (page) => {
