async (page) => {
  // Villager appears at ~(710, 330) in screenshot. Try clicking there
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 710, y: 330 });
  await page.waitForTimeout(2000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  // Check for any dialog or store
  const dialogs = await page.evaluate(() => {
    const ids = ['store', 'dialogue', 'npc-dialogue', 'shop'];
    return ids.map(id => ({ id, display: document.getElementById(id)?.style?.display || 'not found' }));
  });
  return JSON.stringify(dialogs);
}
